local Teams = {}

TeamManager = class("TeamManager", EventObservable)

function TeamManager:init()
    self:registerEvent(S2CLSAllTeamInfo, self.onAllTeamInfo)
    self:registerEvent(S2CLSCreateTeam, self.onCreateTeam)
    self:registerEvent(S2CLSDisbandTeam, self.onDisbandTeam)
    self:registerEvent(S2CLSPlayerTeam, self.onPlayerTeam)
end

function TeamManager.onAllTeamInfo(teamIds)
    for _, teamId in pairs(teamIds) do
        TeamManager.onCreateTeam(teamId)
    end
end

function TeamManager.onCreateTeam(teamId)
    if TeamManager.hasTeam(teamId) then
        return
    end
    table.insert(Teams, teamId)
    local player = PlayerManager:getPlayerByUserId(teamId)
    if not player then
        return
    end
    player:createTeam()
end

function TeamManager.onDisbandTeam(teamId)
    for pos, record in pairs(Teams) do
        if record == teamId then
            table.remove(Teams, pos)
        end
    end
    local player = PlayerManager:getPlayerByUserId(teamId)
    if not player then
        return
    end
    player:disbandTeam()
end

function TeamManager.onPlayerTeam(teamId)
    PlayerManager:getClientPlayer():setTeamId(teamId)
end

function TeamManager.getTeams()
    return Teams
end

function TeamManager.hasTeam(id)
    for _, teamId in pairs(Teams) do
        if teamId == id then
            return true
        end
    end
    return false
end

return TeamManager